// Demo data used when Google Sheets is not yet configured
import { format, subHours, subDays } from "date-fns";

const now = new Date();
const fmt = (d) => format(d, "yyyy-MM-dd HH:mm");

export const DEMO_MECHANICS = [
  { id: "M001", name: "Carlos Ramírez", role: "Senior Mechanic", phone: "555-0101", active: "true" },
  { id: "M002", name: "Ana Torres",     role: "Mechanic",        phone: "555-0102", active: "true" },
  { id: "M003", name: "Luis Mendoza",   role: "Apprentice",      phone: "555-0103", active: "true" },
  { id: "M004", name: "Sofia Vega",     role: "Senior Mechanic", phone: "555-0104", active: "true" },
];

export const DEMO_EQUIPMENT = [
  { id: "EQ001", name: "Excavadora CAT 320",   type: "Excavadora",  serial: "CAT320-2019-001", status: "Activo",     lastService: "2024-11-15", nextService: "2025-02-15" },
