  { id: "EQ004", name: "Montacargas Toyota 5t", type: "Montacargas", serial: "TOY-8FG50-2021",  status: "Activo",     lastService: "2024-11-20", nextService: "2025-02-20" },
  { id: "EQ005", name: "Retroexcavadora JCB",   type: "Retroexcavadora", serial: "JCB-3CX-4521",status: "Inactivo",  lastService: "2024-09-10", nextService: "2024-12-10" },
];

export const DEMO_WORK_ORDERS = [
  { id: "WO-2025-001", equipmentId: "EQ001", equipmentName: "Excavadora CAT 320",   title: "Cambio de aceite y filtros",      status: "Completado",  priority: "Media",  mechanicId: "M001", mechanicName: "Carlos Ramírez", createdAt: fmt(subDays(now,5)), completedAt: fmt(subDays(now,4)) },
  { id: "WO-2025-002", equipmentId: "EQ002", equipmentName: "Grúa Liebherr LTM",    title: "Falla en sistema hidráulico",     status: "En Progreso", priority: "Alta",   mechanicId: "M002", mechanicName: "Ana Torres",     createdAt: fmt(subDays(now,2)), completedAt: "" },
  { id: "WO-2025-003", equipmentId: "EQ003", equipmentName: "Compactadora Bomag",   title: "Revisión de frenos",              status: "Pendiente",   priority: "Baja",   mechanicId: "M003", mechanicName: "Luis Mendoza",   createdAt: fmt(subDays(now,1)), completedAt: "" },
  { id: "WO-2025-004", equipmentId: "EQ004", equipmentName: "Montacargas Toyota 5t","title": "Inspección anual",              status: "En Progreso", priority: "Media",  mechanicId: "M004", mechanicName: "Sofia Vega",     createdAt: fmt(subDays(now,3)), completedAt: "" },
  { id: "WO-2025-005", equipmentId: "EQ001", equipmentName: "Excavadora CAT 320",   title: "Reparación de oruga derecha",    status: "Pendiente",   priority: "Alta",   mechanicId: "M001", mechanicName: "Carlos Ramírez", createdAt: fmt(now),            completedAt: "" },
];

export const DEMO_TIME_ENTRIES = [
  { id: "TE001", workOrderId: "WO-2025-001", mechanicId: "M001", mechanicName: "Carlos Ramírez", clockIn: fmt(subDays(now,4)), clockOut: fmt(subHours(subDays(now,4), -3)), hours: "3.0", notes: "Cambio completo", billable: "true" },
  { id: "TE002", workOrderId: "WO-2025-002", mechanicId: "M002", mechanicName: "Ana Torres",     clockIn: fmt(subHours(now,5)), clockOut: "",                                   hours: "",    notes: "En progreso",   billable: "true" },
  { id: "TE003", workOrderId: "WO-2025-004", mechanicId: "M004", mechanicName: "Sofia Vega",     clockIn: fmt(subDays(now,2)), clockOut: fmt(subHours(subDays(now,2),-6)),    hours: "6.0", notes: "Primera fase",  billable: "true" },
  { id: "TE004", workOrderId: "WO-2025-001", mechanicId: "M001", mechanicName: "Carlos Ramírez", clockIn: fmt(subDays(now,5)), clockOut: fmt(subHours(subDays(now,5),-2)),    hours: "2.0", notes: "Diagnóstico",   billable: "false" },
  { id: "TE005", workOrderId: "WO-2025-004", mechanicId: "M004", mechanicName: "Sofia Vega",     clockIn: fmt(subHours(now,2)), clockOut: "",                                  hours: "",    notes: "",              billable: "true" },
